Identify the vulnerability in the following Solidity code:

```solidity
pragma solidity ^0.8.0;

contract Bank {
    mapping(address => uint) public balances;

    function deposit() external payable {
        balances[msg.sender] += msg.value;
    }

    function withdraw(uint amount) external {
        require(balances[msg.sender] >= amount, "Insufficient balance");
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success);
        balances[msg.sender] -= amount;
    }
}
```

The following Solidity 0.6.x code implements an ERC-20 transfer. Identify the vulnerability and explain how an attacker would exploit it:

```solidity
pragma solidity ^0.6.0;

contract Token {
    mapping(address => uint256) public balances;

    function transfer(address to, uint256 amount) external {
        require(balances[msg.sender] >= amount);
        balances[msg.sender] -= amount;
        balances[to] += amount;  // potential overflow
    }

    function mint(address to, uint256 amount) external {
        balances[to] += amount;
    }
}
```

